CREATE TABLE content_relations (revision_id VARCHAR(36) NOT NULL, entry_id VARCHAR(36) NOT NULL, model_id VARCHAR(36) NOT NULL, field_id VARCHAR(36) NOT NULL, target_entry_id VARCHAR(36) NOT NULL, target_model_id VARCHAR(36) NOT NULL, position TINYINT UNSIGNED NOT NULL, PRIMARY KEY (revision_id, field_id, position), UNIQUE KEY uq_content_relations_target (revision_id, field_id, target_entry_id), KEY idx_content_relations_filter (model_id, field_id, target_entry_id, revision_id, entry_id), KEY idx_content_relations_target_entry (target_model_id, target_entry_id), CONSTRAINT fk_content_relations_revision FOREIGN KEY (revision_id, entry_id, model_id) REFERENCES content_revisions (id, entry_id, model_id), CONSTRAINT fk_content_relations_field FOREIGN KEY (field_id, model_id) REFERENCES content_fields (id, model_id), CONSTRAINT fk_content_relations_target FOREIGN KEY (target_entry_id, target_model_id) REFERENCES content_entries (id, model_id), CONSTRAINT chk_content_relations_position CHECK (position < 50)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_as_cs;
